css_rules.index.css:
@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-[#030305] text-[#E2E2E5] overflow-hidden antialiased;
    font-family: 'JetBrains Mono', monospace;
  }
  ::-webkit-scrollbar { width: 4px; height: 4px; }
  ::-webkit-scrollbar-track { background: #030305; }
  ::-webkit-scrollbar-thumb { background: #1e1e24; }
  ::-webkit-scrollbar-thumb:hover { background: #00f0ff; }
}

css_rules.App.css:
:root {
  --bg-base: #030305;
  --bg-surface: #0B0B0F;
  --bg-surface-hover: #12121A;
  --border-dim: #1C1C24;
  --border-bright: #333340;
  --text-main: #E2E2E5;
  --text-muted: #6B6B78;
  --color-critical: #FF2A2A;
  --color-warning: #FFB014;
  --color-ok: #00FF66;
  --color-info: #00E5FF;
}

.card { @apply bg-[#0B0B0F] border border-[#1C1C24] relative flex flex-col; border-radius: 0; box-shadow: inset 0 0 20px rgba(0,0,0,0.5); }
.card::before, .card::after { content: ''; position: absolute; width: 4px; height: 4px; border: 1px solid var(--border-bright); }
.card::before { top: -1px; left: -1px; border-right: none; border-bottom: none; }
.card::after { bottom: -1px; right: -1px; border-left: none; border-top: none; }

.card-header { @apply bg-[#12121A] border-b border-[#1C1C24] px-4 py-2 flex items-center justify-between uppercase tracking-[0.2em] text-[10px] text-[#80808a] font-bold; }

.tab-item { @apply px-6 h-full flex items-center justify-center text-xs tracking-widest text-gray-500 uppercase cursor-pointer border-r border-[#1C1C24] transition-colors duration-200; }
.tab-item:hover { @apply text-gray-300 bg-[#12121A]; }
.tab-item-active { @apply text-[#00E5FF] bg-[#0B0B0F] border-b-2 border-b-[#00E5FF]; box-shadow: inset 0 -4px 15px -10px rgba(0,229,255,0.5); }

.btn { @apply px-4 py-2 border border-[#1C1C24] bg-[#0B0B0F] text-xs uppercase tracking-widest text-gray-300 transition-all hover:border-[#333340] hover:text-white flex items-center justify-center gap-2; border-radius: 0; }
.btn-primary { @apply border-[#00E5FF] text-[#00E5FF] hover:bg-[#00E5FF]/10; box-shadow: inset 0 0 10px rgba(0,229,255,0.1); }
.btn-danger { @apply border-[#FF2A2A] text-[#FF2A2A] hover:bg-[#FF2A2A]/10; box-shadow: inset 0 0 10px rgba(255,42,42,0.1); }

.badge { @apply px-2 py-0.5 text-[10px] uppercase tracking-wider border flex items-center gap-1 font-bold; border-radius: 0; }
.badge-green { @apply border-[#00FF66]/30 text-[#00FF66] bg-[#00FF66]/10; }
.badge-amber { @apply border-[#FFB014]/30 text-[#FFB014] bg-[#FFB014]/10; }
.badge-red { @apply border-[#FF2A2A]/30 text-[#FF2A2A] bg-[#FF2A2A]/10; box-shadow: 0 0 10px rgba(255,42,42,0.2); }
.badge-blue { @apply border-[#00E5FF]/30 text-[#00E5FF] bg-[#00E5FF]/10; }
.badge-zinc { @apply border-[#333340] text-gray-400 bg-[#12121A]; }

.section-label { @apply text-[#00E5FF] text-xs uppercase tracking-[0.2em] mb-2 block font-bold; }

.th { @apply text-left px-3 py-2 text-[10px] text-gray-500 uppercase tracking-widest border-b border-[#1C1C24] font-normal; }
.table-row { @apply border-b border-[#1C1C24] hover:bg-[#12121A] transition-colors text-xs text-gray-300; }

.alert-critical { @apply border-l-2 border-l-[#FF2A2A] bg-[#FF2A2A]/5 hover:bg-[#FF2A2A]/10 text-white relative; }
.alert-critical::after { content: ''; position: absolute; left: -2px; top: 0; bottom: 0; width: 2px; background: #FF2A2A; box-shadow: 0 0 10px #FF2A2A; }
.alert-warning { @apply border-l-2 border-l-[#FFB014] bg-[#FFB014]/5 text-gray-200; }
.alert-info { @apply border-l-2 border-l-[#00E5FF] bg-[#00E5FF]/5 text-gray-200; }

.dot-online { @apply w-2 h-2 bg-[#00FF66] shadow-[0_0_8px_#00FF66]; }
.dot-degraded { @apply w-2 h-2 bg-[#FFB014] shadow-[0_0_8px_#FFB014]; }
.dot-offline { @apply w-2 h-2 bg-[#FF2A2A] shadow-[0_0_8px_#FF2A2A]; }
.dot-unknown { @apply w-2 h-2 bg-gray-600; }

.ping { @apply absolute inline-flex h-full w-full bg-inherit opacity-75 animate-ping; }
.skeleton { @apply bg-[#1C1C24] animate-pulse; }
.modal-backdrop { @apply fixed inset-0 bg-[#030305]/80 backdrop-blur-sm z-50 flex items-center justify-center; }
.input { @apply bg-[#030305] border border-[#1C1C24] text-gray-200 px-3 py-2 text-xs focus:outline-none focus:border-[#00E5FF] focus:ring-1 focus:ring-[#00E5FF]/50 transition-all rounded-none font-mono; }

components.TopNav.jsx:
import React, { useState, useEffect } from 'react';
import { Activity, Clock, Terminal, ShieldAlert, Network, Settings, Map, CheckSquare } from 'lucide-react';

const TopNav = ({ currentPath, onNavigate }) => {
  const [time, setTime] = useState(new Date());
  useEffect(() => { const timer = setInterval(() => setTime(new Date()), 1000); return () => clearInterval(timer); }, []);
  const tabs = [
    { id: 'dashboard', label: 'DASHBOARD', icon: Activity },
    { id: 'network', label: 'NETWORK MAP', icon: Map },
    { id: 'alerts', label: 'ALERTS', icon: ShieldAlert },
    { id: 'vendor', label: 'VENDOR STATUS', icon: Network },
    { id: 'dia', label: 'DIA CIRCUITS', icon: Activity },
    { id: 'tickets', label: 'TICKETS', icon: CheckSquare },
    { id: 'wazuh', label: 'WAZUH', icon: Terminal },
    { id: 'settings', label: 'SETTINGS', icon: Settings }
  ];

  return (
    <div className='h-12 bg-[#030305] border-b border-[#1C1C24] flex items-center justify-between px-4 select-none shrink-0' data-testid='topnav-container'>
      <div className='flex items-center gap-3'>
        <div className='relative flex items-center justify-center w-6 h-6'>
          <div className='absolute inset-0 border border-[#00E5FF] opacity-50 transform rotate-45'></div>
          <Terminal size={14} className='text-[#00E5FF] relative z-10' />
        </div>
        <div className='flex flex-col leading-none'>
          <span className='text-[#00E5FF] font-bold tracking-[0.3em] text-sm'>IT CMD CTR</span>
          <span className='text-[9px] text-[#6B6B78] tracking-widest uppercase'>SYS.OPS</span>
        </div>
      </div>
      <div className='flex h-full border-l border-[#1C1C24]'>
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = currentPath === tab.id;
          return (
            <button key={tab.id} onClick={() => onNavigate(tab.id)} data-testid={`nav-tab-${tab.id}`} className={`tab-item ${isActive ? 'tab-item-active' : ''}`}>
              <Icon size={14} className='mr-2' />{tab.label}
            </button>
          );
        })}
      </div>
      <div className='flex items-center gap-6'>
        <div className='flex items-center gap-2' data-testid='system-status'>
          <span className='text-[10px] text-[#80808A] tracking-widest uppercase'>NODE.STATUS</span>
          <div className='relative flex items-center justify-center w-3 h-3'>
            <div className='dot-online relative z-10'></div>
            <div className='dot-online ping'></div>
          </div>
        </div>
        <div className='flex items-center gap-2 text-[#E2E2E5]' data-testid='live-clock'>
          <Clock size={14} className='text-[#00E5FF]' />
          <span className='text-sm font-bold tracking-widest font-mono'>{time.toLocaleTimeString('en-US', { hour12: false })}</span>
        </div>
      </div>
    </div>
  );
};
export default TopNav;

components.Layout.jsx:
import React from 'react';
import TopNav from './TopNav';

const Layout = ({ children, currentPath, onNavigate }) => {
  return (
    <div className='h-screen w-screen overflow-hidden bg-[#030305] text-[#E2E2E5] flex flex-col font-mono' data-testid='main-layout'>
      <TopNav currentPath={currentPath} onNavigate={onNavigate} />
      <main className='flex-1 overflow-hidden p-4 relative' data-testid='page-content'>
        <div className='absolute inset-0 pointer-events-none opacity-[0.02]' style={{ backgroundImage: 'linear-gradient(#00E5FF 1px, transparent 1px), linear-gradient(90deg, #00E5FF 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
        <div className='relative z-10 w-full h-full'>
          {children}
        </div>
      </main>
    </div>
  );
};
export default Layout;
